153	            breakpoint="lg"
154	            collapsedWidth={0}
155	            trigger={null}
156	            collapsed={navCollapsed}
157	            onBreakpoint={(broken) => {
158	              setNarrow(broken);
159	              setNavCollapsed(broken);
160	            }}
161	            style={{ borderInlineEnd: `1px solid ${BRAND.border}`, height: '100%' }}
162	          >
163	            {/* Primary nav up top, footer group (Admin · Settings · Documentation)
164	              pinned to the bottom by the flex layout, separated by a hairline. The
165	              primary nav takes the slack and scrolls if it ever exceeds the height,
