267	 */
268	function UserMenu() {
269	  const user = useCurrentUser();
270	  if (!user) return null;
271	
272	  const onLogout = () => {
273	    if (authMode !== 'real') return;
274	    void logout();
275	  };
276	
277	  const items: MenuProps['items'] = [
278	    {
279	      type: 'group',
280	      label: (
281	        <Flex vertical gap={2} style={{ padding: '4px 4px 8px' }}>
282	          <Typography.Text strong style={{ color: BRAND.ink }}>
283	            {user.name}
284	          </Typography.Text>
285	          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
286	            {user.username}
287	          </Typography.Text>
288	          {user.isDev && (
289	            <Tag color="orange" style={{ marginTop: 4, width: 'fit-content' }}>
290	              DEV BYPASS
291	            </Tag>
292	          )}
293	        </Flex>
294	      ),
295	    },
296	    { type: 'divider' },
297	    {
298	      key: 'logout',
299	      icon: <LogoutOutlined />,
300	      label: user.isDev ? 'Sign out (dev bypass)' : 'Sign out',
301	      danger: !user.isDev,
302	      disabled: user.isDev,
303	      onClick: onLogout,
304	    },
305	  ];
306	
307	  return (
308	    <Dropdown menu={{ items }} trigger={['click']} placement="bottomRight">
309	      <Flex align="center" gap={8} style={{ cursor: 'pointer' }}>
310	        <Avatar size="small" style={{ backgroundColor: BRAND.primary, flexShrink: 0 }}>
311	          {initialsOf(user.name)}
312	        </Avatar>
313	        <Typography.Text style={{ color: BRAND.ink }}>{user.name}</Typography.Text>
314	        <DownOutlined style={{ fontSize: 10, color: '#8c8c8c' }} />
315	      </Flex>
316	    </Dropdown>
317	  );
318	}
