1	import {
2	  ApartmentOutlined,
3	  ArrowLeftOutlined,
4	  EditOutlined,
5	  UserOutlined,
6	} from '@ant-design/icons';
7	import { App, Button, Card, Empty, Flex, Input, Modal, Select, Table, Tag, Typography } from 'antd';
8	import type { ColumnsType } from 'antd/es/table';
9	import { useState } from 'react';
10	import { useNavigate, useParams } from 'react-router-dom';
11	
12	import { type AdminUser, listAdminUsers } from '../api/admin';
13	import {
14	  type AssetDetail as AssetDetailData,
15	  type ComposingSuite,
16	  type LineageNode,
17	  getAsset,
18	  updateAsset,
19	} from '../api/assets';
20	import { useIsWorkspaceAdmin } from '../auth/useMe';
21	import { AssetHealthTag } from '../components/assets/AssetHealthTag';
22	import { IncidentsPanel } from '../components/assets/IncidentsPanel';
23	import { runHealth } from '../components/assets/health';
24	import { AsyncBody } from '../components/AsyncBody';
25	import { Page } from '../components/layout/Page';
26	import { formatTimestamp } from '../components/results/resultsFormat';
27	import SimpleList from '../components/SimpleList';
28	import { useAsyncData } from '../hooks/useAsyncData';
29	import { errorMessage } from '../utils/errors';
30	
31	/**
32	 * Asset detail (`/assets/:assetId`, #760) — identity header, health across the
33	 * composing suites (the acceptance criterion: renders ≥2 suites on a shared
34	 * asset), and upstream/downstream lineage lists. Links out to each suite and its
35	 * latest run. Read-only apart from the workspace-Admin-only description edit
36	 * (ADR 0034 §4); no navigation inversion (phase 4).
37	 */
38	export function AssetDetail() {
39	  const navigate = useNavigate();
40	  const { assetId } = useParams<{ assetId: string }>();
41	  const { state, reload } = useAsyncData(() => {
42	    if (!assetId) throw new Error('no asset');
43	    return getAsset(assetId);
44	  });
45	
46	  return (
47	    <Page gap={16}>
48	      <div>
49	        <Button
50	          type="text"
51	          icon={<ArrowLeftOutlined />}
52	          onClick={() => navigate('/assets')}
53	          style={{ paddingLeft: 0 }}
54	        >
55	          Assets
56	        </Button>
57	      </div>
58	      <AsyncBody state={state} loadingText="Loading asset…" errorTitle="Failed to load asset">
59	        {(asset) => (
60	          <AssetDetailBody
61	            asset={asset}
62	            onOpenRun={(id) => navigate(`/results/${id}`)}
63	            onChanged={reload}
64	          />
65	        )}
66	      </AsyncBody>
67	    </Page>
68	  );
69	}
70	
71	function AssetDetailBody({
72	  asset,
73	  onOpenRun,
74	  onChanged,
75	}: {
76	  asset: AssetDetailData;
77	  onOpenRun: (runId: string) => void;
78	  onChanged: () => void;
79	}) {
80	  const { summary } = asset;
81	  const navigate = useNavigate();
82	  // Asset-metadata mutation is workspace-Admin-only (ADR 0034 §4; backend 403s
83	  // everyone else) — the edit affordance renders only for admins. This gate is
84	  // nav convenience, not the security boundary (that's the PATCH's 403).
85	  const isAdmin = useIsWorkspaceAdmin();
86	  return (
87	    <Flex vertical gap={20}>
88	      <Flex justify="space-between" align="flex-start" gap={12} wrap>
89	        <Flex vertical gap={4} style={{ minWidth: 0 }}>
90	          <Typography.Title level={3} style={{ margin: 0 }}>
91	            {summary.name}
92	          </Typography.Title>
93	          <Typography.Text type="secondary" copyable>
94	            {summary.namespace}
95	          </Typography.Text>
96	        </Flex>
97	        <Flex gap={8} align="center">
98	          {summary.env && <Tag>{summary.env}</Tag>}
99	          <AssetHealthTag summary={summary} />
100	        </Flex>
101	      </Flex>
102	
103	      <DescriptionBlock
104	        assetId={summary.id}
105	        description={summary.description}
106	        canEdit={isAdmin}
107	        onChanged={onChanged}
108	      />
109	
110	      {/* Mount-gated (not closure-gated) on adminness: useAsyncData only re-runs
111	          its fetcher on [nonce], so a fetcher that closed over a still-false
112	          `isAdmin` would never re-fire once /me resolves (admin deep-link/refresh
113	          race). Mounting the block only when adminness is KNOWN true means its
114	          on-mount fetch always runs with the right identity — and a non-admin
115	          structurally never hits the admin-only endpoint. */}
116	      {isAdmin && (
117	        <OwnerBlock
118	          assetId={summary.id}
119	          ownerUserId={summary.owner_user_id}
120	          onChanged={onChanged}
121	        />
122	      )}
123	
124	      <SuitesSection
125	        suites={asset.suites}
126	        onOpenSuite={(id) => navigate(`/suites/${id}`)}
127	        onOpenRun={onOpenRun}
128	      />
129	
130	      <IncidentsPanel
131	        assetId={summary.id}
132	        permissionBySuite={Object.fromEntries(
133	          asset.suites.map((s) => [s.suite_id, s.my_permission]),
134	        )}
135	      />
136	
137	      <Flex gap={16} wrap align="stretch">
138	        <LineagePanel
139	          title="Upstream"
140	          nodes={asset.upstream}
141	          emptyHint="No known upstream sources."
142	        />
143	        <LineagePanel
144	          title="Downstream"
145	          nodes={asset.downstream}
146	          emptyHint="No known downstream consumers."
147	        />
148	      </Flex>
149	    </Flex>
150	  );
151	}
152	
153	/**
154	 * The asset description + the workspace-Admin-only inline edit (#760). Owner
155	 * reassignment lives in its own `OwnerBlock` below (#773).
156	 */
157	function DescriptionBlock({
158	  assetId,
159	  description,
160	  canEdit,
161	  onChanged,
162	}: {
163	  assetId: string;
164	  description: string | null;
165	  canEdit: boolean;
166	  onChanged: () => void;
167	}) {
168	  const { message } = App.useApp();
169	  const [editing, setEditing] = useState(false);
170	  const [draft, setDraft] = useState('');
171	  const [saving, setSaving] = useState(false);
172	
173	  const openEditor = () => {
174	    setDraft(description ?? '');
175	    setEditing(true);
176	  };
177	
178	  const onSave = async () => {
179	    setSaving(true);
180	    try {
181	      // Empty draft clears the description (explicit null — the PATCH's
182	      // omitted-vs-null semantics make that an intentional unset).
183	      await updateAsset(assetId, { description: draft.trim() || null });
184	      message.success('Description updated');
185	      setEditing(false);
186	      onChanged();
187	    } catch (err) {
188	      message.error(`Update failed: ${errorMessage(err)}`);
189	    } finally {
190	      setSaving(false);
191	    }
192	  };
193	
194	  if (!description && !canEdit) return null;
195	  return (
196	    <>
197	      <Flex gap={8} align="baseline" wrap>
198	        {description ? (
199	          <Typography.Paragraph style={{ margin: 0 }}>{description}</Typography.Paragraph>
200	        ) : (
201	          <Typography.Text type="secondary">No description yet.</Typography.Text>
202	        )}
203	        {canEdit && (
204	          <Button type="link" size="small" icon={<EditOutlined />} onClick={openEditor}>
205	            Edit
206	          </Button>
207	        )}
208	      </Flex>
209	      <Modal
210	        title="Edit asset description"
211	        open={editing}
212	        onOk={() => void onSave()}
213	        okText="Save"
214	        confirmLoading={saving}
215	        onCancel={() => setEditing(false)}
216	        destroyOnHidden
217	      >
218	        <Input.TextArea
219	          rows={3}
220	          maxLength={1024}
221	          showCount
222	          value={draft}
223	          onChange={(e) => setDraft(e.target.value)}
224	          placeholder="What is this asset, and who should care when it breaks?"
225	        />
226	      </Modal>
227	    </>
228	  );
229	}
230	
231	/**
232	 * Asset owner + the workspace-Admin-only reassignment (#773). Asset owners feed
233	 * ADR 0034 §3 incident routing, so keeping them assignable matters. The picker is
234	 * sourced from `GET /admin/users` (itself admin-only — a clean fit, since the
235	 * whole control is admin-gated); the current owner renders as a display
236	 * name/email, never a bare UUID, once the user list resolves.
237	 *
238	 * **Mounted only for admins** (the parent gates on `isAdmin`) — so the on-mount
239	 * user-list fetch always runs with adminness known, and a non-admin structurally
240	 * never calls the admin-only endpoint. This gate is nav convenience — the PATCH's
241	 * `require_workspace_admin` 403 is the security boundary.
242	 */
243	function OwnerBlock({
244	  assetId,
245	  ownerUserId,
246	  onChanged,
247	}: {
248	  assetId: string;
249	  ownerUserId: string | null;
250	  onChanged: () => void;
251	}) {
252	  const { message } = App.useApp();
253	  // Fetches on mount — safe because this component only mounts for admins.
254	  const { state } = useAsyncData(listAdminUsers);
255	  const [editing, setEditing] = useState(false);
256	  // Controlled select value: `undefined` = unassigned (renders the placeholder).
257	  const [draft, setDraft] = useState<string | undefined>(undefined);
258	  const [saving, setSaving] = useState(false);
259	
260	  const loadFailed = state.status === 'error';
261	  const users: AdminUser[] = state.status === 'ok' ? state.data : [];
262	  const label = (u: AdminUser) => u.display_name || u.email;
263	  const owner = users.find((u) => u.id === ownerUserId);
264	  // Prefer the resolved name/email; fall back to the raw id only if the list
265	  // hasn't loaded or the owner is somehow not in it (never leave a blank).
266	  const ownerText = ownerUserId === null ? 'Unassigned' : owner ? label(owner) : ownerUserId;
267	
268	  const openEditor = () => {
269	    setDraft(ownerUserId ?? undefined);
270	    setEditing(true);
271	  };
272	
273	  const onSave = async () => {
274	    setSaving(true);
275	    try {
276	      // `undefined` draft → explicit null (unassign); otherwise the chosen id.
277	      await updateAsset(assetId, { owner_user_id: draft ?? null });
278	      message.success('Owner updated');
279	      setEditing(false);
280	      onChanged();
281	    } catch (err) {
282	      message.error(`Update failed: ${errorMessage(err)}`);
283	    } finally {
284	      setSaving(false);
285	    }
286	  };
287	
288	  return (
289	    <>
290	      <Flex gap={8} align="center" wrap>
291	        <UserOutlined style={{ color: '#8c8c8c' }} />
292	        <Typography.Text type="secondary">Owner:</Typography.Text>
293	        {ownerUserId === null ? (
294	          <Typography.Text type="secondary">{ownerText}</Typography.Text>
295	        ) : (
296	          <Typography.Text>{ownerText}</Typography.Text>
297	        )}
298	        <Button
299	          type="link"
300	          size="small"
301	          icon={<EditOutlined />}
302	          onClick={openEditor}
303	          disabled={loadFailed}
304	        >
305	          Reassign owner
306	        </Button>
307	        {/* A failed /admin/users read must not degrade to a silently-empty
308	            picker — say so (mirrors the AssetHealthLead unavailable state). */}
309	        {loadFailed && (
310	          <Typography.Text type="secondary">
311	            The user list is unavailable right now.
312	          </Typography.Text>
313	        )}
314	      </Flex>
315	      <Modal
316	        title="Reassign asset owner"
317	        open={editing}
318	        onOk={() => void onSave()}
319	        okText="Save"
320	        confirmLoading={saving}
321	        onCancel={() => setEditing(false)}
322	        destroyOnHidden
323	      >
324	        <Select<string>
325	          style={{ width: '100%' }}
326	          placeholder="Unassigned"
327	          allowClear
328	          showSearch
329	          loading={state.status === 'loading'}
330	          value={draft}
331	          onChange={(value) => setDraft(value)}
332	          optionFilterProp="label"
333	          options={users.map((u) => ({ value: u.id, label: label(u) }))}
334	        />
335	      </Modal>
336	    </>
337	  );
338	}
339	
340	function SuitesSection({
341	  suites,
342	  onOpenSuite,
343	  onOpenRun,
344	}: {
345	  suites: ComposingSuite[];
346	  onOpenSuite: (suiteId: string) => void;
347	  onOpenRun: (runId: string) => void;
348	}) {
349	  const columns: ColumnsType<ComposingSuite> = [
350	    {
351	      title: 'Suite',
352	      dataIndex: 'name',
353	      render: (name: string, suite) => (
354	        <Button type="link" style={{ padding: 0 }} onClick={() => onOpenSuite(suite.suite_id)}>
355	          {name}
356	        </Button>
357	      ),
358	    },
359	    {
360	      title: 'Access',
361	      dataIndex: 'my_permission',
362	      width: 100,
363	      render: (level: string) => <Tag>{level}</Tag>,
364	    },
365	    {
366	      title: 'Health',
367	      key: 'health',
368	      width: 120,
369	      render: (_: unknown, suite) => {
370	        const { label, color } = runHealth(suite.latest_run);
371	        return <Tag color={color}>{label}</Tag>;
372	      },
373	    },
374	    {
375	      title: 'Checks',
376	      key: 'checks',
377	      width: 90,
378	      align: 'center',
379	      render: (_: unknown, suite) => {
380	        const r = suite.latest_run;
381	        return r.checks_total === 0 ? '—' : `${r.checks_passed} / ${r.checks_total}`;
382	      },
383	    },
384	    {
385	      title: 'Last run',
386	      key: 'last_run',
387	      width: 200,
388	      render: (_: unknown, suite) => {
389	        const r = suite.latest_run;
