53	  });
54	});
55	
56	describe('buildAssetTree', () => {
57	  it('roots by namespace and nests db → schema → table, leaf carries the asset', () => {
58	    const a = asset({ id: 'a1', namespace: 'snowflake://acct', name: 'ANALYTICS.PUBLIC.ORDERS' });
