1	import type { AssetSummary, RunOutcome } from '../../api/assets';
2	
3	/**
4	 * Asset health derivation (#760) — pure, so it can be unit-tested without
5	 * rendering antd (kept out of the `.tsx` so the tag component can fast-refresh).
6	 *
7	 * Health considers BOTH axes the Results surface distinguishes (`resultsFormat`'s
8	 * `RUN_STATUS_COLORS` conventions): the run's *execution* status and the checks'
9	 * *data-quality* severity. Precedence:
10	 * - a failing check tier present            → that tier (warn < fail < critical)
11	 * - latest run failed operationally         → "Run failed" (error — never green:
12	 *   a failed run wrote no results, so severity alone would read passing)
13	 * - latest run still queued/running         → "Queued"/"Running" (not green yet)
14	 * - latest run cancelled, nothing evaluated → "Cancelled"
15	 * - a finished run, all evaluated passed    → "Passing"
16	 * - nothing has run yet                     → "No runs"
17	 */
18	export type Health = { label: string; color: string };
19	
20	const SEVERITY_HEALTH: Record<'warn' | 'fail' | 'critical', Health> = {
21	  warn: { label: 'Warning', color: 'warning' },
22	  fail: { label: 'Failing', color: 'error' },
23	  critical: { label: 'Critical', color: 'magenta' },
24	};
25	
26	// Execution-status healths, colour-matched to resultsFormat.RUN_STATUS_COLORS.
27	const RUN_FAILED_HEALTH: Health = { label: 'Run failed', color: 'error' };
28	const STATUS_HEALTH: Record<string, Health> = {
29	  queued: { label: 'Queued', color: 'default' },
30	  running: { label: 'Running', color: 'processing' },
31	  cancelled: { label: 'Cancelled', color: 'warning' },
32	};
33	
34	/**
35	 * Asset-level health from the summary aggregation (severity + run-state flags).
36	 *
37	 * The **compact roll-up** of both axes below, for space-constrained rows (the
38	 * assets tree/table). Where there is room to be precise — the asset detail — render
39	 * `connectionHealth` and `suiteHealth` side by side instead (#803).
40	 */
41	export function assetHealth(
42	  summary: Pick<
43	    AssetSummary,
44	    'worst_severity' | 'last_run_at' | 'has_failed_run' | 'has_active_run'
45	  >,
46	): Health {
47	  if (summary.worst_severity) return SEVERITY_HEALTH[summary.worst_severity];
48	  if (summary.has_failed_run) return RUN_FAILED_HEALTH;
49	  if (summary.has_active_run) return STATUS_HEALTH.running;
50	  if (summary.last_run_at !== null) return { label: 'Passing', color: 'success' };
51	  return { label: 'No runs', color: 'default' };
52	}
53	
54	/**
55	 * **Connection health (#803)** — *could DataQ reach and execute against the
56	 * datasource behind this asset?* Says nothing about whether the data is good.
57	 *
58	 * Derivation (no polling loop — read straight off the runs already recorded):
59	 * - a latest run whose execution `failed`, or any check that `error`ed (the
60	 *   datasource threw) → **Errors**;
61	 * - any `skip` (a precondition wasn't met — e.g. the batch hasn't landed) →
62	 *   **Degraded**: it executed, it just found nothing to check;
63	 * - a run in flight → **Running**; a clean concluded run → **Reachable**;
64	 * - nothing has ever run → **No runs** (unknown, not healthy).
65	 */
66	export function connectionHealth(
67	  summary: Pick<
68	    AssetSummary,
69	    'has_operational_error' | 'has_skip' | 'has_active_run' | 'last_run_at'
70	  >,
71	): Health {
72	  if (summary.has_operational_error) return { label: 'Errors', color: 'error' };
73	  if (summary.has_skip) return { label: 'Degraded', color: 'warning' };
74	  if (summary.has_active_run) return STATUS_HEALTH.running;
75	  if (summary.last_run_at !== null) return { label: 'Reachable', color: 'success' };
76	  return { label: 'No runs', color: 'default' };
77	}
78	
79	/**
80	 * **Suite health (#803)** — the ADR 0005 severity-weighted verdict of the suites
81	 * on this asset. Purely about the *data*; operational `error`/`skip` results are
82	 * excluded (they're `connectionHealth`'s business, per #122).
83	 *
84	 * Crucially this keys "Passing" off `checks_total > 0` — the count of *evaluated*
85	 * checks — not off "a run happened". A run that failed operationally, or one whose
86	 * checks all skipped, evaluated nothing, so it reports **No data** rather than a
87	 * green "Passing" it hasn't earned (the bug the old single signal had once the
88	 * operational flags were pulled out of it).
89	 */
90	export function suiteHealth(
91	  summary: Pick<AssetSummary, 'worst_severity' | 'checks_total' | 'has_active_run' | 'last_run_at'>,
92	): Health {
93	  if (summary.worst_severity) return SEVERITY_HEALTH[summary.worst_severity];
94	  if (summary.has_active_run) return STATUS_HEALTH.running;
95	  if (summary.checks_total > 0) return { label: 'Passing', color: 'success' };
96	  if (summary.last_run_at !== null) return { label: 'No data', color: 'default' };
97	  return { label: 'No runs', color: 'default' };
98	}
99	
100	/** Per-suite health from its latest run (execution status + severity). */
101	export function runHealth(run: RunOutcome): Health {
102	  if (run.run_id === null) return { label: 'No runs', color: 'default' };
103	  if (run.worst_severity) return SEVERITY_HEALTH[run.worst_severity];
104	  if (run.status === 'failed') return RUN_FAILED_HEALTH;
105	  const byStatus = run.status !== null ? STATUS_HEALTH[run.status] : undefined;
106	  if (byStatus) return byStatus;
107	  return { label: 'Passing', color: 'success' };
108	}

