1	import { ArrowRightOutlined, DatabaseOutlined } from '@ant-design/icons';
2	import { Card, Empty, Flex, Grid, Spin, Tag, Typography } from 'antd';
3	import { useNavigate } from 'react-router-dom';
4	
5	import { type AssetSummary, listAssets } from '../../api/assets';
6	import { AssetHealthTag } from '../assets/AssetHealthTag';
7	import { useAsyncData } from '../../hooks/useAsyncData';
8	import { BRAND } from '../../theme';
9	
10	/**
11	 * Asset-health lead (`/dashboard`, ADR 0034 navigation inversion, #773) — the
12	 * dashboard now *leads* with asset-level health: how many assets DataQ monitors,
13	 * how many need attention, how many have a run in flight. Everything is derived
14	 * from the existing `/assets` list read (no new endpoint) and filtered to the
15	 * caller's grants by the backend, so this leaks nothing.
16	 *
17	 * Click-through is preserved end to end: the tiles and "View all assets" go to
18	 * `/assets`; each attention row opens `/assets/:id` (→ its suites/runs).
19	 */
20	
21	/** An asset "needs attention" when a check tier is failing or its latest run
22	 *  failed operationally — an active-but-unconcluded run is *in progress*, not
23	 *  failing (mirrors `assetHealth`'s precedence). */
24	function needsAttention(a: AssetSummary): boolean {
25	  return a.worst_severity !== null || a.has_failed_run;
26	}
27	
28	/** Attention ordering: critical > fail > warn > operational run failure. The
29	 *  backend list arrives (namespace, name)-alphabetical, so without this a page
30	 *  of warns could hide a critical asset behind the "+N more" fold. */
31	const SEVERITY_RANK: Record<'warn' | 'fail' | 'critical', number> = {
32	  warn: 1,
33	  fail: 2,
34	  critical: 3,
35	};
36	function attentionRank(a: AssetSummary): number {
37	  return a.worst_severity ? SEVERITY_RANK[a.worst_severity] : 0;
38	}
39	
40	/** How many attention rows to surface inline before deferring to the full list. */
41	const ATTENTION_PREVIEW = 5;
42	
43	/** The backend caps `GET /assets` at 200 rows (its default == its max). A result
44	 *  exactly at the cap means the widget may be looking at a truncated slice — the
45	 *  counts must say so rather than silently undercount. */
46	const LIST_CAP = 200;
47	
48	export function AssetHealthLead() {
49	  const navigate = useNavigate();
50	  const { state } = useAsyncData(() => listAssets());
51	
52	  return (
53	    <Card
54	      size="small"
55	      styles={{ body: { paddingTop: 12 } }}
56	      title={
57	        <Flex align="center" gap={8}>
58	          <DatabaseOutlined style={{ color: BRAND.primary }} />
59	          <span>Asset health</span>
60	        </Flex>
61	      }
62	      extra={
63	        <Typography.Link onClick={() => navigate('/assets')}>
64	          View all assets <ArrowRightOutlined />
65	        </Typography.Link>
66	      }
67	    >
68	      {state.status === 'loading' && <Spin />}
69	      {state.status === 'error' && (
70	        <Typography.Text type="secondary">Asset health is unavailable right now.</Typography.Text>
71	      )}
72	      {state.status === 'ok' && (
73	        <AssetHealthBody
74	          assets={state.data}
75	          onOpenList={() => navigate('/assets')}
76	          onOpenAsset={(id) => navigate(`/assets/${id}`)}
77	        />
78	      )}
79	    </Card>
80	  );
81	}
82	
83	function AssetHealthBody({
84	  assets,
85	  onOpenList,
86	  onOpenAsset,
87	}: {
88	  assets: AssetSummary[];
89	  onOpenList: () => void;
90	  onOpenAsset: (id: string) => void;
91	}) {
92	  const screens = Grid.useBreakpoint();
93	  const stacked = screens.sm === false;
94	
95	  if (assets.length === 0) {
96	    return (
97	      <Empty
98	        image={Empty.PRESENTED_IMAGE_SIMPLE}
99	        description="No monitored assets yet — give a suite a run target and it will appear here."
100	      />
101	    );
102	  }
103	
104	  // Worst first (stable within a tier — Array.prototype.sort is stable), so a
105	  // critical asset can never hide behind five alphabetically-earlier warns.
106	  const attention = assets
107	    .filter(needsAttention)
108	    .sort((x, y) => attentionRank(y) - attentionRank(x));
109	  const active = assets.filter((a) => !needsAttention(a) && a.has_active_run);
110	  const truncated = assets.length >= LIST_CAP;
111	
112	  const tiles: { label: string; value: number; tone: string }[] = [
113	    { label: 'Monitored', value: assets.length, tone: BRAND.ink },
114	    {
115	      label: 'Need attention',
116	      value: attention.length,
117	      tone: attention.length ? '#cf1322' : BRAND.ink,
118	    },
119	    { label: 'In progress', value: active.length, tone: BRAND.ink },
120	  ];
121	
122	  return (
123	    <Flex vertical gap={16}>
124	      {/* Summary strip — each tile is a click-through to the full assets list. */}
125	      <Flex gap={12} vertical={stacked}>
126	        {tiles.map((t) => (
127	          <Card
128	            key={t.label}
129	            size="small"
130	            className="dq-card--interactive"
131	            style={{ flex: 1, cursor: 'pointer' }}
132	            styles={{ body: { padding: '12px 16px' } }}
133	            onClick={onOpenList}
134	          >
135	            <Flex vertical gap={2}>
136	              <Typography.Text type="secondary" style={{ fontSize: 12 }}>
137	                {t.label}
138	              </Typography.Text>
139	              <Typography.Text strong style={{ fontSize: 22, color: t.tone }}>
140	                {t.value}
141	              </Typography.Text>
142	            </Flex>
143	          </Card>
144	        ))}
145	      </Flex>
146	
147	      {/* Honest truncation: at the cap we can't know how many assets exist
148	          beyond this slice, so the tiles above are a lower bound — say so
149	          explicitly instead of silently undercounting. */}
150	      {truncated && (
151	        <Typography.Text type="secondary" style={{ fontSize: 12 }}>
152	          Showing the first {LIST_CAP} assets — open Assets for the full list.
153	        </Typography.Text>
154	      )}
155	
156	      {/* Attention list: the assets a data owner should look at first. When all
157	          is well, say so rather than showing an empty box. */}
158	      {attention.length === 0 ? (
159	        <Typography.Text type="secondary">All monitored assets are healthy.</Typography.Text>
160	      ) : (
161	        <Flex vertical gap={8}>
162	          <Typography.Text strong style={{ fontSize: 13 }}>
163	            Needs attention
164	          </Typography.Text>
165	          {attention.slice(0, ATTENTION_PREVIEW).map((a) => (
166	            <Flex
167	              key={a.id}
168	              className="dq-suite-row"
169	              justify="space-between"
170	              align="center"
171	              gap={12}
172	              wrap
173	              onClick={() => onOpenAsset(a.id)}
174	              style={{ cursor: 'pointer', padding: '6px 8px', borderRadius: 6 }}
175	            >
176	              <Flex vertical gap={0} style={{ minWidth: 0 }}>
177	                <Typography.Text strong ellipsis style={{ maxWidth: 360 }}>
178	                  {a.name}
179	                </Typography.Text>
180	                <Typography.Text type="secondary" style={{ fontSize: 12 }} ellipsis>
181	                  {a.namespace}
182	                </Typography.Text>
183	              </Flex>
184	              <Flex gap={8} align="center">
185	                {a.env && <Tag>{a.env}</Tag>}
186	                <AssetHealthTag summary={a} />
187	              </Flex>
188	            </Flex>
189	          ))}
190	          {attention.length > ATTENTION_PREVIEW && (
191	            <Typography.Link onClick={onOpenList}>
192	              +{attention.length - ATTENTION_PREVIEW} more
193	            </Typography.Link>
194	          )}
195	        </Flex>
196	      )}
197	    </Flex>
198	  );
199	}

